package com.JavaOperator;

public class RelationalOperator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int a = 5;
		int b = 2;
		
		boolean m = a==b;
		
		System.out.println("Equal "+m);
		
m = a!=b;
		
		System.out.println("Not Equal "+m);
		
m = a<=b;
		
		System.out.println("Less than Equal "+m);
		
m = a>=b;
		
		System.out.println("Greater than Equal "+m);
		
m = a>b;
		
		System.out.println("Greater than "+m);
		
m = a<b;
		
		System.out.println("Less than "+m);

	}

}
